  1→import { useMemo, useRef } from 'react';
  2→import { TOOLS } from './tools';
  3→import { createWallDrawHandler } from './handlers/wallDrawHandler';
  4→import { createSelectHandler } from './handlers/selectHandler';
  5→import { createDimensionPlaceHandler } from './handlers/dimensionPlaceHandler';
  6→import { createDoorPlaceHandler } from './handlers/doorPlaceHandler';
  7→import { createWindowPlaceHandler } from './handlers/windowPlaceHandler';
  8→import { createColumnPlaceHandler } from './handlers/columnPlaceHandler';
  9→import { createRoomPlaceHandler } from './handlers/roomPlaceHandler';
 10→import { createBeamPlaceHandler } from './handlers/beamPlaceHandler';
 11→import { createSlabPlaceHandler } from './handlers/slabPlaceHandler';
 12→import { createStairPlaceHandler } from './handlers/stairPlaceHandler';
 13→import { createSectionPlaceHandler } from './handlers/sectionPlaceHandler';
 14→import { createLandingPlaceHandler } from './handlers/landingPlaceHandler';
 15→import { createFixturePlaceHandler } from './handlers/fixturePlaceHandler';
 16→import { createElevationSelectHandler } from './handlers/elevationSelectHandler';
 17→
 18→function createReadOnlyHandler() {
 19→  return {
 20→    onMouseDown() {},
 21→    onMouseMove() {},
 22→    onMouseUp() {},
 23→    onDoubleClick() {},
 24→    onKeyDown() {},
 25→    getCursor() {
 26→      return 'default';
 27→    },
 28→  };
 29→}
 30→
 31→export function useEditorTool({ activeTool, dispatch, editorDispatch, project, getFloor, activeFloorId, viewport, snapEnabled, selectedId, selectedType, toolState, viewMode }) {
 32→  const getFloorRef = useRef(getFloor);
 33→  getFloorRef.current = getFloor;
 34→
 35→  const handler = useMemo(() => {
 36→    if (viewMode?.startsWith('elevation_')) {
 37→      return createElevationSelectHandler({
 38→        dispatch,
 39→        editorDispatch,
 40→        project,
 41→        getFloor: (...args) => getFloorRef.current(...args),
 42→        activeFloorId,
 43→        viewport,
 44→        snapEnabled,
 45→        viewMode,
 46→      });
 47→    }
 48→
 49→    if (viewMode !== 'plan') {
 50→      return createReadOnlyHandler();
 51→    }
 52→
 53→    const ctx = {
 54→      dispatch, editorDispatch,
 55→      getFloor: (...args) => getFloorRef.current(...args),
 56→      activeFloorId, viewport, snapEnabled,
 57→    };
 58→
 59→    switch (activeTool) {
 60→      case TOOLS.DIMENSION:
 61→        return createDimensionPlaceHandler(ctx);
 62→      case TOOLS.WALL:
 63→        return createWallDrawHandler(ctx);
 64→      case TOOLS.BEAM:
 65→        return createBeamPlaceHandler(ctx);
 66→      case TOOLS.STAIR:
 67→        return createStairPlaceHandler(ctx);
 68→      case TOOLS.SECTION:
