174→      }
175→
176→      if (!toolState.dragging || !selectedId) return;
177→
178→      const floor = getFloor(activeFloorId);
179→      if (!floor) return;
180→      const dx = modelPos.x - toolState.startPos.x;
181→      const dy = modelPos.y - toolState.startPos.y;
182→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
183→
184→      if (selectedType === 'wall') {
185→        const wall = floor.walls.find(w => w.id === selectedId);
186→        if (!wall) return;
187→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
188→
189→        if (toolState.dragType === 'handle') {
190→          const handle = toolState.handle;
191→          const oppositeKey = handle === 'start' ? 'end' : 'start';
192→          const oppositePoint = resolved[oppositeKey];
193→          let nextPoint = modelPos;
194→          let nextAttachment = null;
195→
196→          if (e.shiftKey) {
197→            const dx = modelPos.x - oppositePoint.x;
198→            const dy = modelPos.y - oppositePoint.y;
199→            const angle = Math.atan2(dy, dx);
