355→              y: stair.startPoint.y + dy,
356→            },
357→          },
358→        });
359→        editorDispatch({
360→          type: 'UPDATE_TOOL_STATE',
361→          payload: { startPos: modelPos },
362→        });
363→      } else if (selectedType === 'landing') {
364→        const landing = (floor.landings || []).find(l => l.id === selectedId);
365→        if (!landing) return;
366→        dispatch({
367→          type: 'LANDING_UPDATE',
368→          floorId: activeFloorId,
369→          landing: {
370→            id: landing.id,
371→            position: {
372→              x: landing.position.x + dx,
373→              y: landing.position.y + dy,
374→            },
375→          },
376→        });
377→        editorDispatch({
378→          type: 'UPDATE_TOOL_STATE',
379→          payload: { startPos: modelPos },
380→        });
381→      } else if (selectedType === 'slab') {
382→        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
383→          return;
384→        }
385→        const slab = (floor.slabs || []).find(s => s.id === selectedId);
386→        if (!slab) return;
387→
388→        const boundaryPoints = slab.boundaryPoints.map((point, index) => (
