390→        ));
391→
392→        dispatch({
393→          type: 'SLAB_UPDATE',
394→          floorId: activeFloorId,
395→          slab: {
396→            id: slab.id,
397→            boundaryPoints,
398→          },
399→        });
400→        editorDispatch({
401→          type: 'UPDATE_TOOL_STATE',
402→          payload: { startPos: modelPos },
403→        });
404→      } else if (selectedType === 'door' || selectedType === 'window') {
405→        // Slide along parent wall
406→        const items = selectedType === 'door' ? floor.doors : floor.windows;
407→        const item = items.find(i => i.id === selectedId);
408→        if (!item) return;
409→
410→        const wall = floor.walls.find(w => w.id === item.wallId);
411→        if (!wall) return;
412→
413→        const newOffset = projectPointOnWall(wall, modelPos);
414→        const clampedOffset = clampWallOpeningOffset(wallLength(wall), item.width, newOffset);
415→
416→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
417→        dispatch({
418→          type: updateType,
419→          floorId: activeFloorId,
420→          [selectedType]: { id: item.id, offset: clampedOffset },
421→        });
422→
423→        editorDispatch({
424→          type: 'UPDATE_TOOL_STATE',
425→          payload: { startPos: modelPos },
426→        });
427→      }
428→    },
429→
430→    onMouseUp(modelPos, e, toolState) {
431→      if (toolState.dragging && toolState.dragType === 'marquee') {
432→        const floor = getFloor(activeFloorId);
433→        const bounds = normalizeRectBounds(toolState.startPos || modelPos, toolState.currentPos || modelPos);
434→        const size = rectSize(bounds);
435→        const minimumSize = SNAP_DISTANCE_PX / viewport.zoom;
436→
437→        if (!floor || (size.width < minimumSize && size.height < minimumSize)) {
438→          editorDispatch({ type: 'DESELECT' });
439→        } else {
440→          const regionSelection = collectPlanRegionSelection(floor, bounds);
441→          if (regionSelection.objectCount) {
442→            editorDispatch({
443→              type: 'SET_REGION_SELECTION',
444→              bounds: regionSelection.bounds,
445→              selection: regionSelection.selection,
446→            });
447→          } else {
448→            editorDispatch({ type: 'DESELECT' });
449→          }
450→        }
451→
452→        editorDispatch({
453→          type: 'UPDATE_TOOL_STATE',
454→          payload: {
455→            dragging: false,
456→            dragType: null,
457→            handle: null,
458→            handleIndex: null,
459→            startPos: null,
460→            currentPos: null,
461→          },
462→        });
463→        return;
464→      }
465→
466→      if (toolState.dragging) {
467→        editorDispatch({
468→          type: 'UPDATE_TOOL_STATE',
469→          payload: {
470→            dragging: false,
471→            dragType: null,
472→            handle: null,
473→            handleIndex: null,
474→            startPos: null,
475→            originalPos: null,
476→            currentPos: null,
477→          },
478→        });
479→      }
480→    },
481→
482→    onKeyDown(e, toolState, selectedId, selectedType) {
483→      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'd' && selectedId && selectedType === 'column') {
484→        e.preventDefault();
485→        const floor = getFloor(activeFloorId);
486→        if (!floor) return;
487→        const column = (floor.columns || []).find(c => c.id === selectedId);
488→        if (!column) return;
489→        const duplicate = duplicateColumn(column);
490→        dispatch({ type: 'COLUMN_DUPLICATE', floorId: activeFloorId, column: duplicate });
491→        editorDispatch({ type: 'SELECT_OBJECT', id: duplicate.id, objectType: 'column' });
492→        return;
493→      }
494→
495→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
496→        const floor = getFloor(activeFloorId);
497→        if (!floor) return;
498→        if (selectedType === 'wall') {
499→          dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
500→        } else if (selectedType === 'door') {
501→          dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
502→        } else if (selectedType === 'window') {
503→          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
504→        } else if (selectedType === 'column') {
505→          dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
506→        } else if (selectedType === 'fixture') {
507→          dispatch({ type: 'FIXTURE_DELETE', floorId: activeFloorId, fixtureId: selectedId });
508→        } else if (selectedType === 'beam') {
509→          dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
510→        } else if (selectedType === 'stair') {
511→          dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
512→        } else if (selectedType === 'landing') {
513→          dispatch({ type: 'LANDING_DELETE', floorId: activeFloorId, landingId: selectedId });
514→        } else if (selectedType === 'annotation') {
515→          dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
516→        } else if (selectedType === 'slab') {
517→          dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId, slabId: selectedId });
518→        } else if (selectedType === 'sectionCut') {
519→          dispatch({ type: 'SECTION_DELETE', floorId: activeFloorId, sectionId: selectedId });
520→        } else if (selectedType === 'room') {
521→          dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
522→        }
523→        editorDispatch({ type: 'DESELECT' });
524→      }
525→    },
526→
527→    getCursor(toolState) {
528→      if (toolState.dragType === 'marquee') return 'crosshair';
529→      if (toolState.dragging) return 'grabbing';
530→      return 'default';
531→    },
532→  };
533→}
