249→function addCylinder(group, materialKey, rTop, rBot, h, segs, px, py, pz, materialPalette, isSelected) {
250→  const geo = new THREE.CylinderGeometry(Math.max(rTop, 0.5), Math.max(rBot, 0.5), Math.max(h, 0.5), segs);
251→  const mesh = new THREE.Mesh(geo, createMeshMaterial(materialPalette, materialKey, isSelected));
252→  mesh.position.set(px, py, pz);
253→  mesh.castShadow = true;
254→  mesh.receiveShadow = true;
255→  addOutline(mesh, materialPalette, isSelected);
256→  group.add(mesh);
257→  return mesh;
258→}
