407→function createFixtureObject(descriptor, materialPalette, isSelected) {
408→  const builder = FIXTURE_BUILDERS[descriptor.fixtureType];
409→  if (!builder) {
410→    return createBoxObject(descriptor, materialPalette, isSelected);
411→  }
412→
413→  const group = new THREE.Group();
414→  const W = descriptor.size.x;
415→  const H = descriptor.size.y;
416→  const D = descriptor.size.z;
417→
418→  builder(group, W, H, D, materialPalette, isSelected);
419→
420→  group.position.copy(planPointToWorld(descriptor.center, descriptor.baseElevation));
421→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
422→
423→  return group;
424→}
