117→export function buildWallSolidSegments(context) {
118→  if (context.renderLength <= EPSILON || context.wallTop - context.wallBase <= EPSILON) {
119→    return [];
120→  }
121→
122→  const segments = [];
123→  let cursor = 0;
124→  let segmentIndex = 0;
125→
126→  const pushSegment = (startAlong, endAlong, baseElevation, topElevation) => {
127→    if (endAlong - startAlong <= EPSILON) return;
128→    if (topElevation - baseElevation <= EPSILON) return;
129→
130→    segmentIndex += 1;
131→    segments.push({
132→      id: `${context.wall.id}-segment-${segmentIndex}`,
133→      wallId: context.wall.id,
134→      floorId: context.floorId,
135→      startPoint: positionOnWall(context.renderWall, startAlong),
136→      endPoint: positionOnWall(context.renderWall, endAlong),
137→      thickness: context.renderWall.thickness,
138→      baseElevation,
139→      topElevation,
140→    });
141→  };
142→
143→  for (const opening of context.openings) {
144→    const openingStart = Math.max(cursor, opening.startAlong);
145→    const openingEnd = Math.max(openingStart, opening.endAlong);
146→
147→    pushSegment(cursor, openingStart, context.wallBase, context.wallTop);
148→
149→    if (opening.visibleBaseElevation > context.wallBase + EPSILON) {
150→      pushSegment(
151→        openingStart,
152→        openingEnd,
153→        context.wallBase,
154→        Math.min(opening.visibleBaseElevation, context.wallTop)
155→      );
156→    }
157→
158→    if (opening.visibleTopElevation < context.wallTop - EPSILON) {
159→      pushSegment(
160→        openingStart,
161→        openingEnd,
162→        Math.max(opening.visibleTopElevation, context.wallBase),
163→        context.wallTop
164→      );
165→    }
166→
167→    cursor = Math.max(cursor, openingEnd);
168→  }
169→
170→  pushSegment(cursor, context.renderLength, context.wallBase, context.wallTop);
171→  return segments;
172→}
