383→function buildBedFixture(group, W, H, D, palette, sel) {
384→  const mat = 'fixture_bed';
385→  // Bed frame
386→  addBox(group, mat, W, H * 0.30, D, 0, H * 0.15, 0, palette, sel);
387→  // Headboard
388→  addBox(group, 'fixtureAccentWood', W, H * 0.65, D * 0.04, 0, H * 0.325, -D * 0.48, palette, sel);
389→  // Mattress (slightly inset, sits on frame)
390→  addBox(group, mat, W * 0.94, H * 0.30, D * 0.90, 0, H * 0.45, D * 0.03, palette, sel);
391→  // Left pillow
392→  addBox(group, 'fixtureAccentCeramic', W * 0.32, H * 0.12, D * 0.16, -W * 0.22, H * 0.66, -D * 0.36, palette, sel);
393→  // Right pillow
394→  addBox(group, 'fixtureAccentCeramic', W * 0.32, H * 0.12, D * 0.16, W * 0.22, H * 0.66, -D * 0.36, palette, sel);
