396→
397→const FIXTURE_BUILDERS = {
398→  kitchenTop: buildKitchenTopFixture,
399→  toilet: buildToiletFixture,
400→  lavatory: buildLavatoryFixture,
401→  table: buildTableFixture,
402→  tv: buildTvFixture,
403→  sofa: buildSofaFixture,
404→  bed: buildBedFixture,
405→};
406→
407→function createFixtureObject(descriptor, materialPalette, isSelected) {
408→  const builder = FIXTURE_BUILDERS[descriptor.fixtureType];
409→  if (!builder) {
410→    return createBoxObject(descriptor, materialPalette, isSelected);
411→  }
412→
413→  const group = new THREE.Group();
414→  const W = descriptor.size.x;
415→  const H = descriptor.size.y;
416→  const D = descriptor.size.z;
417→
418→  builder(group, W, H, D, materialPalette, isSelected);
419→
420→  group.position.copy(planPointToWorld(descriptor.center, descriptor.baseElevation));
421→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
422→
423→  return group;
424→}
425→
426→// ── Dispatcher ──
427→
428→function createObjectForDescriptor(descriptor, materialPalette, isSelected) {
429→  if (descriptor.geometry === 'prism') {
430→    return createPrismObject(descriptor, materialPalette, isSelected);
431→  }
432→
433→  if (descriptor.geometry === 'stair') {
434→    return createStairObject(descriptor, materialPalette, isSelected);
435→  }
436→
437→  if (descriptor.geometry === 'window') {
438→    return createWindowObject(descriptor, materialPalette, isSelected);
439→  }
440→
441→  if (descriptor.geometry === 'fixture') {
442→    return createFixtureObject(descriptor, materialPalette, isSelected);
443→  }
444→
445→  return createBoxObject(descriptor, materialPalette, isSelected);
446→}
447→
448→function matchesSelection(descriptor, selection) {
449→  if (!selection?.selectedId || selection.selectedType !== descriptor.kind) return false;
450→  return (descriptor.metadata?.sourceId || descriptor.id) === selection.selectedId;
451→}
452→
453→function assignPreviewMetadata(object, descriptor, floor) {
454→  const previewTarget = {
455→    kind: descriptor.kind,
456→    sourceId: descriptor.metadata?.sourceId || descriptor.id,
457→    floorId: descriptor.metadata?.floorId || floor.floorId,
458→  };
459→
460→  object.traverse((node) => {
461→    node.userData = {
462→      ...node.userData,
463→      previewTarget,
464→    };
465→  });
466→}
467→
468→export function buildPreviewObjectRoot(sceneDescriptor, materialPalette, selection = null) {
469→  const root = new THREE.Group();
470→  root.name = 'preview-root';
471→
472→  for (const floor of sceneDescriptor.floors) {
473→    const floorGroup = new THREE.Group();
474→    floorGroup.name = `floor-${floor.floorId}`;
475→    floorGroup.visible = floor.visible;
476→    floorGroup.userData = {
477→      floorId: floor.floorId,
478→      floorName: floor.name,
479→      elevation: floor.elevation,
480→    };
481→
482→    for (const descriptor of floor.objects) {
483→      const isSelected = matchesSelection(descriptor, selection);
484→      const object = createObjectForDescriptor(descriptor, materialPalette, isSelected);
485→      object.name = descriptor.id;
486→      object.userData = {
487→        id: descriptor.id,
488→        kind: descriptor.kind,
489→        metadata: descriptor.metadata,
490→      };
491→      assignPreviewMetadata(object, descriptor, floor);
492→      floorGroup.add(object);
493→    }
494→
495→    root.add(floorGroup);
496→  }
497→
498→  return root;
499→}
